          break;
        case 'analytics':
          _trackAnalyticsEvent(payload);
          break;
        case 'navigate':
          _handleNativeNavigation(payload);
          break;
        case 'storage_set':
          _handleStorageSet(payload);
          break;
        case 'storage_get':
          _handleStorageGet(payload);
          break;
        default:
          debugPrint('Unknown message type: $type');
      }
    } catch (e) {
      debugPrint('Error parsing JavaScript message: $e');
    }
  }

  void _handleCameraRequest(String message) async {
