  Future<Map<String, dynamic>?> _openCamera(
      Map<String, dynamic> options) async {
    final cameras = await availableCameras();
    if (cameras.isEmpty) return null;

    final preferFront = options['facing'] == 'front';
    final camera = cameras.firstWhere(
      (c) => c.lensDirection ==
          (preferFront
              ? CameraLensDirection.front
              : CameraLensDirection.back),
      orElse: () => cameras.first,
    );

    if (!mounted) return null;

    final result = await Navigator.of(context).push<String>(
      MaterialPageRoute(
        builder: (context) => CameraScreen(camera: camera),
      ),
    );

    if (result != null) {
      final bytes = await File(result).readAsBytes();
      final base64Image = base64Encode(bytes);
      return {
        'path': result,
        'base64': base64Image,
        'mimeType': 'image/jpeg',
      };
    }
    return null;
  }

  void _handleNotificationRequest(String message) async {
    try {
      final data = jsonDecode(message);
      final action = data['action'] as String?;

      switch (action) {
        case 'requestPermission':
          final settings = await _firebaseMessaging.requestPermission();
          final jsonResult = jsonEncode({
            'type': 'notification_permission',
            'granted': settings.authorizationStatus ==
                AuthorizationStatus.authorized,
          });
          _controller.runJavaScript(
            'window.onNativeMessage && window.onNativeMessage($jsonResult);',
          );
          break;
        case 'getToken':
          final token = await _firebaseMessaging.getToken();
          if (token != null) {
            _sendTokenToWebView(token);
          }
          break;
        case 'subscribe':
          final topic = data['topic'] as String?;
          if (topic != null) {
            await _firebaseMessaging.subscribeToTopic(topic);
            debugPrint('Subscribed to topic: $topic');
          }
          break;
        case 'unsubscribe':
          final topic = data['topic'] as String?;
          if (topic != null) {
            await _firebaseMessaging.unsubscribeFromTopic(topic);
            debugPrint('Unsubscribed from topic: $topic');
          }
          break;
      }
    } catch (e) {
      debugPrint('Error handling notification request: $e');
    }
  }

